<template><view class="page"><view class="card" v-for="a in addresses" :key="a.id" @click="choose(a)"><text class="title">{{a.name}} {{a.phone}}</text><text class="muted">{{a.province}}{{a.city}}{{a.district}}{{a.detail}}</text><view class="ops"><text @click.stop="edit(a.id)">编辑</text><text @click.stop="def(a.id)">默认</text><text @click.stop="remove(a.id)">删除</text></view></view><button class="add primary" @click="edit('')">新增地址</button></view></template><script setup lang="ts">import { ref } from 'vue';import { onLoad,onShow } from '@dcloudio/uni-app';import { addressApi } from '@/services/address';const addresses=ref<any[]>([]),select=ref(false);async function load(){addresses.value=(await addressApi.list()).data||[]}function choose(a:any){if(select.value){uni.$emit('addressSelected',a);uni.navigateBack()}}function edit(id:any){uni.navigateTo({url:'/pages/address/edit/index'+(id?'?id='+id:'')})}async function def(id:any){await addressApi.setDefault(id);load()}async function remove(id:any){await addressApi.remove(id);load()}onLoad((o:any)=>select.value=o.select==='1');onShow(load)</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c;padding-bottom:130rpx}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{display:block;font-size:34rpx;font-weight:900}.muted{display:block;color:#8d8175;font-size:24rpx;margin-top:12rpx}.ops{display:flex;gap:28rpx;margin-top:20rpx;color:#b97700}.add{position:fixed;left:20rpx;right:20rpx;bottom:24rpx;height:86rpx;line-height:86rpx;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
